import math


def gini_impurity(labels):
    """Gini impurity of a label set."""
    n = len(labels)
    if n == 0:
        return 0.0
    counts = {}
    for label in labels:
        counts[label] = counts.get(label, 0) + 1
    return 1.0 - sum((c / n) ** 2 for c in counts.values())


def information_gain(parent, left, right):
    """Information gain (Gini-based) of splitting parent into left and right."""
    n = len(parent)
    n_left = len(left)
    n_right = len(right)
    if n_left == 0 or n_right == 0:
        return 0.0
    parent_impurity = gini_impurity(parent)
    child_impurity = (
        (n_left / n) * gini_impurity(left)
        + (n_right / n) * gini_impurity(right)
    )
    return parent_impurity - child_impurity


def best_split(X, y):
    """Find the feature and threshold that maximize information gain."""
    best_feature = None
    best_threshold = None
    best_gain = 0.0
    n_features = len(X[0]) if X else 0

    for feature_idx in range(n_features):
        values = sorted(set(row[feature_idx] for row in X))
        if len(values) <= 1:
            continue
        for i in range(len(values) - 1):
            threshold = (values[i] + values[i + 1]) / 2.0
            left = [y[j] for j in range(len(X)) if X[j][feature_idx] <= threshold]
            right = [y[j] for j in range(len(X)) if X[j][feature_idx] > threshold]
            gain = information_gain(y, left, right)
            if gain > best_gain:
                best_gain = gain
                best_feature = feature_idx
                best_threshold = threshold

    return best_feature, best_threshold, best_gain
